#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, r, c, K;
        scanf("%d %d %d %d %d", &N, &M, &r, &c, &K);
        int count = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= M; j++) {
                if (abs(i - r) + abs(j - c) <= K && (abs(i - r) == abs(j - c))) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

