code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int r = sc.nextInt();
            int c = sc.nextInt();
            int K = sc.nextInt();
            int count = 0;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    if (Math.abs(i - r) + Math.abs(j - c) <= K && (Math.abs(i - r) == Math.abs(j - c))) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

